//! RF physics CPU bridge.
//!
//! Runtime mirror of `Gnosis.RFPhysicsCpuRuntime`. The model is intentionally
//! conservative: ambient RF/white noise supplies potential channels, but only a
//! thresholded witness signal activates a bounded 10-bit projection frame.

use crate::pleromatic_frame::{PleromaticFrame, PleromaticMediaType};
use gnosis_frf::prelude::{IntoParallelIterator, ParallelIterator};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

pub const TEN_BIT_FRAME_WIDTH: u16 = 10;
pub const MONSTER_VECTOR_FLOOR: u32 = 196_884;
pub const BULEY_BISIDED_RHYTHM_GRAIN: u16 = 16;

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub struct RfAntennaRig {
    pub compute_antennas: u16,
    pub witness_antennas: u16,
    pub reflection_paths: u16,
    pub impedance_witnesses: u16,
    pub phase_channels: u16,
}

impl RfAntennaRig {
    pub const fn reflected_one_port() -> Self {
        Self {
            compute_antennas: 1,
            witness_antennas: 0,
            reflection_paths: 1,
            impedance_witnesses: 1,
            phase_channels: 2,
        }
    }

    pub const fn effective_compute_paths(self) -> u16 {
        self.compute_antennas + self.reflection_paths
    }

    pub const fn witness_channels(self) -> u16 {
        self.witness_antennas + self.reflection_paths + self.impedance_witnesses
    }
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub struct RfSignalGate {
    pub potential_channels: u32,
    pub witness_signal: u16,
    pub activation_threshold: u16,
}

impl RfSignalGate {
    pub const fn active_channels(self) -> u16 {
        if self.witness_signal >= self.activation_threshold
            && self.potential_channels >= MONSTER_VECTOR_FLOOR
        {
            TEN_BIT_FRAME_WIDTH
        } else {
            0
        }
    }
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub struct RfProjection {
    pub selected_channels: u16,
    pub vented_complement: u32,
    pub projected_frame_width: u16,
    pub redundancy_reserve: u16,
    pub race_candidate_count: u16,
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub struct TenBitAeonFrame {
    pub side_select: u8,
    pub lifted_slot: u8,
    pub contracted_slot: u8,
    pub spark_parity: u8,
}

impl TenBitAeonFrame {
    pub const fn from_signal_gate(gate: RfSignalGate) -> Option<Self> {
        if gate.active_channels() != TEN_BIT_FRAME_WIDTH {
            return None;
        }

        Some(Self {
            side_select: 1,
            lifted_slot: 1,
            contracted_slot: 2,
            spark_parity: (gate.witness_signal % 2) as u8,
        })
    }

    pub const fn bit_width(self) -> u16 {
        let _ = self;
        1 + 4 + 4 + 1
    }

    pub const fn lifted_score(self, rhythm_grain: u16) -> u16 {
        self.lifted_slot as u16 * rhythm_grain
    }

    pub const fn contracted_score(self, rhythm_grain: u16) -> u16 {
        self.contracted_slot as u16 * rhythm_grain
    }

    pub const fn score(self, rhythm_grain: u16) -> u16 {
        self.lifted_score(rhythm_grain) + self.contracted_score(rhythm_grain)
    }

    pub const fn buley_bisided_score(self) -> u16 {
        self.score(BULEY_BISIDED_RHYTHM_GRAIN)
    }
}

#[derive(Serialize, Deserialize, Clone, Copy, Debug, PartialEq, Eq)]
pub struct RfPhysicsCpuObservation {
    pub rig: RfAntennaRig,
    pub gate: RfSignalGate,
    pub projection: RfProjection,
    pub frame: Option<TenBitAeonFrame>,
}

impl RfPhysicsCpuObservation {
    pub fn observe_one_port(gate: RfSignalGate) -> Self {
        let rig = RfAntennaRig::reflected_one_port();
        let race_candidate_count = race_signal_candidates(gate);
        let selected_channels = gate.active_channels();
        let vented_complement = gate
            .potential_channels
            .saturating_sub(selected_channels as u32);

        Self {
            rig,
            gate,
            projection: RfProjection {
                selected_channels,
                vented_complement,
                projected_frame_width: TEN_BIT_FRAME_WIDTH,
                redundancy_reserve: rig.witness_channels(),
                race_candidate_count,
            },
            frame: TenBitAeonFrame::from_signal_gate(gate),
        }
    }

    pub fn observe_waterfall_frame(frame: &PleromaticFrame, activation_threshold: u16) -> Self {
        let max_energy = frame.data.iter().copied().max().unwrap_or(0) as u16;
        let potential_channels = (frame.data.len() as u32).max(MONSTER_VECTOR_FLOOR);
        Self::observe_one_port(RfSignalGate {
            potential_channels,
            witness_signal: max_energy,
            activation_threshold,
        })
    }

    pub fn is_computable(&self) -> bool {
        self.rig.effective_compute_paths() == 2
            && self.rig.impedance_witnesses > 0
            && self.gate.active_channels() == TEN_BIT_FRAME_WIDTH
            && self.frame.is_some()
    }

    pub fn to_monster_mesh_frame(&self, source_id: impl Into<String>) -> PleromaticFrame {
        let mut attributes = HashMap::new();
        attributes.insert("rf_runtime".to_string(), "physics_cpu".to_string());
        attributes.insert(
            "rf_compute_paths".to_string(),
            self.rig.effective_compute_paths().to_string(),
        );
        attributes.insert(
            "rf_witness_channels".to_string(),
            self.rig.witness_channels().to_string(),
        );
        attributes.insert(
            "rf_potential_channels".to_string(),
            self.gate.potential_channels.to_string(),
        );
        attributes.insert(
            "rf_selected_channels".to_string(),
            self.projection.selected_channels.to_string(),
        );
        attributes.insert(
            "rf_vented_complement".to_string(),
            self.projection.vented_complement.to_string(),
        );
        attributes.insert(
            "rf_redundancy_reserve".to_string(),
            self.projection.redundancy_reserve.to_string(),
        );
        attributes.insert(
            "rf_race_candidate_count".to_string(),
            self.projection.race_candidate_count.to_string(),
        );
        attributes.insert(
            "rf_computable".to_string(),
            self.is_computable().to_string(),
        );

        if let Some(frame) = self.frame {
            attributes.insert(
                "rf_buley_bisided_side_select".to_string(),
                frame.side_select.to_string(),
            );
            attributes.insert(
                "rf_buley_bisided_lifted_score".to_string(),
                frame.lifted_score(BULEY_BISIDED_RHYTHM_GRAIN).to_string(),
            );
            attributes.insert(
                "rf_buley_bisided_contracted_score".to_string(),
                frame
                    .contracted_score(BULEY_BISIDED_RHYTHM_GRAIN)
                    .to_string(),
            );
            attributes.insert(
                "rf_buley_bisided_score".to_string(),
                frame.buley_bisided_score().to_string(),
            );
            attributes.insert(
                "rf_buley_bisided_spark_parity".to_string(),
                frame.spark_parity.to_string(),
            );
            attributes.insert(
                "rf_buley_bisided_rhythm_grain".to_string(),
                BULEY_BISIDED_RHYTHM_GRAIN.to_string(),
            );
        }

        let data = self
            .frame
            .map(|frame| {
                vec![
                    frame.side_select,
                    frame.lifted_slot,
                    frame.contracted_slot,
                    frame.spark_parity,
                ]
            })
            .unwrap_or_default();

        PleromaticFrame {
            seq: 0,
            timestamp_ms: 0,
            media_type: PleromaticMediaType::Abstract("RfPhysicsCpu".to_string()),
            level: crate::pleromatic_core::TRIPLE_POINT.closure_value,
            phase: 0,
            deficit: if self.is_computable() { 0.0 } else { 1.0 },
            barcode: crate::acoustic::PersistenceBarcode {
                beta1: self.rig.witness_channels() as u32,
                lifespan: self.projection.selected_channels as u32,
                dilation: 1.0,
                density: if self.is_computable() { 1.0 } else { 0.0 },
            },
            data,
            attributes,
            source_id: source_id.into(),
        }
    }
}

pub fn race_signal_candidates(gate: RfSignalGate) -> u16 {
    (0..gate.active_channels() as usize)
        .into_par_iter()
        .map(|_| 1_u16)
        .reduce(|| 0_u16, |left, right| left + right)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn one_port_impedance_witness_promotes_enough_signal() {
        let observation = RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
            potential_channels: MONSTER_VECTOR_FLOOR,
            witness_signal: 20,
            activation_threshold: 20,
        });

        assert!(observation.is_computable());
        assert_eq!(observation.rig.effective_compute_paths(), 2);
        assert_eq!(observation.rig.witness_channels(), 2);
        assert_eq!(
            observation.projection.selected_channels,
            TEN_BIT_FRAME_WIDTH
        );
        assert_eq!(observation.projection.redundancy_reserve, 2);
        assert_eq!(
            observation.projection.race_candidate_count,
            TEN_BIT_FRAME_WIDTH
        );
        assert_eq!(
            observation.frame.expect("frame").bit_width(),
            TEN_BIT_FRAME_WIDTH
        );
        let frame = observation.frame.expect("frame");
        assert_eq!(frame.lifted_score(BULEY_BISIDED_RHYTHM_GRAIN), 16);
        assert_eq!(frame.contracted_score(BULEY_BISIDED_RHYTHM_GRAIN), 32);
        assert_eq!(frame.buley_bisided_score(), 48);
    }

    #[test]
    fn noise_without_signal_stays_below_compute_floor() {
        let observation = RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
            potential_channels: MONSTER_VECTOR_FLOOR,
            witness_signal: 0,
            activation_threshold: 20,
        });

        assert!(!observation.is_computable());
        assert_eq!(observation.projection.selected_channels, 0);
        assert!(observation.frame.is_none());
    }

    #[test]
    fn projection_frame_records_signal_and_vented_complement() {
        let observation = RfPhysicsCpuObservation::observe_one_port(RfSignalGate {
            potential_channels: MONSTER_VECTOR_FLOOR,
            witness_signal: 20,
            activation_threshold: 20,
        });

        let frame = observation.to_monster_mesh_frame("rf-one-port");
        assert_eq!(frame.source_id, "rf-one-port");
        assert_eq!(frame.data, vec![1, 1, 2, 0]);
        assert_eq!(
            frame.attributes.get("rf_runtime").map(String::as_str),
            Some("physics_cpu")
        );
        assert_eq!(
            frame.attributes.get("rf_computable").map(String::as_str),
            Some("true")
        );
        assert_eq!(
            frame
                .attributes
                .get("rf_vented_complement")
                .map(String::as_str),
            Some("196874")
        );
        assert_eq!(
            frame
                .attributes
                .get("rf_redundancy_reserve")
                .map(String::as_str),
            Some("2")
        );
        assert_eq!(
            frame
                .attributes
                .get("rf_race_candidate_count")
                .map(String::as_str),
            Some("10")
        );
        assert_eq!(
            frame
                .attributes
                .get("rf_buley_bisided_lifted_score")
                .map(String::as_str),
            Some("16")
        );
        assert_eq!(
            frame
                .attributes
                .get("rf_buley_bisided_contracted_score")
                .map(String::as_str),
            Some("32")
        );
        assert_eq!(
            frame
                .attributes
                .get("rf_buley_bisided_score")
                .map(String::as_str),
            Some("48")
        );
    }

    #[test]
    fn waterfall_frame_energy_drives_witness_signal() {
        let frame = PleromaticFrame::spectrum_waterfall(
            "rtl_sdr_live".to_string(),
            4,
            2,
            vec![0, 5, 20, 64, 3, 8, 12, 31],
            2_048_000,
            Some(162_400_000),
            None,
            None,
            None,
            None,
        );
        let observation = RfPhysicsCpuObservation::observe_waterfall_frame(&frame, 20);

        assert_eq!(observation.gate.witness_signal, 64);
        assert_eq!(observation.gate.potential_channels, MONSTER_VECTOR_FLOOR);
        assert!(observation.is_computable());
    }
}
